  ('social-worker-moex-02841', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '針對新移民高齡案主，多元文化綜合性服務模式的敘述，下列何者不適宜？', '["對案主文化有充分認識與尊重", "服務人員只使用主流文化族群所通用的語言", "能以新移民家庭整體健康需求為照顧服務的目標", "發展以該文化相容的處遇技巧"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
